import { NextRequest, NextResponse } from "next/server";
import { auth } from "@/lib/auth";
import { cmsPrisma } from "@/lib/prisma-cms";

export async function GET(req: NextRequest) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const patientCode = session.user.patientCode;
    if (!patientCode) {
      return NextResponse.json({ data: { data: [], total: 0, page: 1, pageSize: 10, totalPages: 0 } });
    }

    const { searchParams } = new URL(req.url);
    const page         = parseInt(searchParams.get("page")     ?? "1",  10);
    const pageSize     = parseInt(searchParams.get("pageSize") ?? "10", 10);
    const statusFilter = searchParams.get("status") ?? "";

    const cmsPatient = await cmsPrisma.cmsPatient.findUnique({
      where: { code: patientCode },
      select: { id: true },
    });

    if (!cmsPatient) {
      return NextResponse.json({ data: { data: [], total: 0, page: 1, pageSize: 10, totalPages: 0 } });
    }

    // CMS status: "1" = paid, "2" = void/cancelled, "205"/"210" = partial/other
    const where = {
      queue: { idPatient: cmsPatient.id },
      status: { not: "2" as const },
    };

    const [total, payments] = await Promise.all([
      cmsPrisma.cmsPaymentHistory.count({ where }),
      cmsPrisma.cmsPaymentHistory.findMany({
        where,
        orderBy: { inputDate: "desc" },
        skip: (page - 1) * pageSize,
        take: pageSize,
        include: {
          queue: { select: { code: true } },
        },
      }),
    ]);

    const data = payments.map((p) => {
      const s = p.status ?? "";
      const status = s === "2" ? "refunded"
        : s === "1" ? "paid"
        : "pending";
      return {
        id:            Number(p.id),
        queueCode:     p.queue.code ?? "",
        date:          p.inputDate.toISOString(),
        receiptNo:     p.orNum ?? "",
        totalAmount:   Number(p.payAmount ?? 0),
        paymentMethod: p.paymentType ?? "CASH",
        status,
      };
    });

    const filtered = statusFilter && statusFilter !== "all"
      ? data.filter((p) => p.status === statusFilter)
      : data;

    return NextResponse.json({
      data: { data: filtered, total, page, pageSize, totalPages: Math.ceil(total / pageSize) },
    });
  } catch (error) {
    console.error("[GET_PAYMENTS]", error);
    return NextResponse.json({ error: "Failed to fetch payments" }, { status: 500 });
  }
}
